// Filter items from last 24 hours and format them
const now = new Date();
const oneDayAgo = new Date(now.getTime() - 24 * 60 * 60 * 1000);

const allItems = [];

for (const item of $input.all()) {
  const pubDate = new Date(item.json.pubDate || item.json.isoDate || '');

  // Skip items older than 24 hours
  if (pubDate < oneDayAgo) continue;

  allItems.push({
    json: {
      title: item.json.title || '',
      link: item.json.link || item.json.url || '',
      description: (item.json.contentSnippet || item.json.description || '').substring(0, 1000),
      pubDate: pubDate.toISOString(),
      sourceName: item.json._sourceName || 'Unknown',
      sourceCategory: item.json._sourceCategory || 'general'
    }
  });
}

return allItems.length > 0 ? allItems : [{ json: { _empty: true } }];

// Deduplicate: remove items whose URL already exists in DB
const newItems = $('Has Items?').all();
const existingArticles = $('Get Existing Articles (48h)').all();

const existingUrls = new Set(
  existingArticles.map(a => a.json.source_url).filter(Boolean)
);

const existingHashes = new Set(
  existingArticles.map(a => a.json.content_hash).filter(Boolean)
);

// Simple title hash for dedup
function titleHash(title) {
  return title
    .toLowerCase()
    .replace(/[^a-z0-9\s]/g, '')
    .split(/\s+/)
    .filter(w => !['the','a','an','is','are','was','were','in','on','at','to','for','of','and','or','but','with','by','from','as','its','it','this','that','will','has','have','had'].includes(w))
    .sort()
    .join(' ');
}

const dedupedItems = [];
const seenHashes = new Set();

for (const item of newItems) {
  const url = item.json.link;
  const hash = titleHash(item.json.title);

  if (existingUrls.has(url)) continue;
  if (existingHashes.has(hash)) continue;
  if (seenHashes.has(hash)) continue;

  seenHashes.add(hash);
  dedupedItems.push({
    json: {
      ...item.json,
      content_hash: hash
    }
  });
}

// Limit to 15 candidates per run
return dedupedItems.slice(0, 15);

// Batch items for GPT processing (groups of 5)
const items = $input.all();
const batches = [];

for (let i = 0; i < items.length; i += 5) {
  const batch = items.slice(i, i + 5);
  batches.push({
    json: {
      batch: batch.map(item => ({
        title: item.json.title,
        link: item.json.link,
        description: item.json.description,
        pubDate: item.json.pubDate,
        sourceName: item.json.sourceName,
        sourceCategory: item.json.sourceCategory,
        content_hash: item.json.content_hash
      }))
    }
  });
}

return batches.length > 0 ? batches : [{ json: { _empty: true } }];

// Parse GPT response and filter publishable articles
const results = [];

for (const item of $input.all()) {
  try {
    let parsed = item.json;

    // Handle if response is in message.content
    if (parsed.message && parsed.message.content) {
      parsed = JSON.parse(parsed.message.content);
    }

    if (!parsed.items) continue;

    for (const article of parsed.items) {
      if (!article.publish || article.relevance_score < 6) continue;
      if (!article.title || !article.content || !article.slug) continue;

      // Ensure slug is unique by adding timestamp
      const slug = article.slug + '-' + Date.now().toString(36);

      results.push({
        json: {
          title: article.title,
          slug: slug,
          content: article.content,
          summary: article.summary,
          twitter_text: article.twitter_text || '',
          category: article.category || 'general',
          tags: article.tags || [],
          source_url: article.original_url || '',
          source_name: article.source_name || 'Unknown',
          source_title: article.title,
          meta_description: article.meta_description || article.summary,
          relevance_score: article.relevance_score,
          status: 'published',
          published_at: new Date().toISOString(),
          content_hash: article.title.toLowerCase().replace(/[^a-z0-9\s]/g, '').split(/\s+/).sort().join(' ')
        }
      });
    }
  } catch (e) {
    // Skip unparseable responses
  }
}

// Cap at 7 articles per run
return results.slice(0, 7);
